import axios, { AxiosResponse } from 'axios'

import { Restaurant } from '../types'

interface BaseApi {
  getRestaurants: () => Promise<Restaurant[]>
  getRestaurantById: (id: string) => Promise<Restaurant>
  getRestaurantsByCategory: (category: string) => Promise<Restaurant[]>
}

export const BASE_URL = 'https://mealdrop.netlify.app/.netlify/functions/restaurants'

const isMockedEnvironment =
  !!import.meta.env.STORYBOOK ||
  import.meta.env.NODE_ENV === 'test' ||
  (globalThis as any).__vitest_browser__

const apiCache = new Map()

const apiGet = async <T>(url: string): Promise<AxiosResponse<T>> => {
  // do not cache when testing to avoid flakyness
  if (!isMockedEnvironment && apiCache.has(url)) {
    return apiCache.get(url)
  }

  const response = await axios.get<T>(url)

  if (!isMockedEnvironment) {
    apiCache.set(url, response)
  }

  return response
}

class RestaurantsApi implements BaseApi {
  async getRestaurants() {
    const { data: restaurants } = await apiGet<Restaurant[]>(BASE_URL)

    return restaurants
  }

  async getRestaurantById(id: string) {
    const { data: restaurant, status } = await apiGet<Restaurant>(`${BASE_URL}?id=${id}`)

    if (status === 404) {
      throw { response: { status: 404 } }
    }

    return restaurant
  }

  async getRestaurantsByCategory(category: string) {
    const { data: restaurants } = await apiGet<Restaurant[]>(`${BASE_URL}?category=${category}`)

    return restaurants
  }
}

export const api = new RestaurantsApi()

import { useRef, useEffect } from 'react'
import * as React from 'react'
import { createPortal } from 'react-dom'

type Props = {
  selector: string
}

export const Portal: React.FC<React.PropsWithChildren<Props>> = ({ children, selector }) => {
  const ref = useRef<Element | null>(null)

  useEffect(() => {
    const element = document.querySelector<Element>(selector)
    if (element) {
      ref.current = element
    }
  }, [selector])

  return ref.current ? createPortal(children, ref.current) : null
}

import * as React from 'react'
import { CSSTransition } from 'react-transition-group'

import { Portal } from '../Portal'
import { useKey } from '../../hooks/useKeyboard'
import { Button } from '../Button'
import { useLockBodyScroll } from '../../hooks/useBodyScrollLock'

import { ModalContent, TopBar, Backdrop } from './Modal.styles'

type ModalProps = {
  isOpen: boolean
  onClose: () => void
}

export const Modal: React.FC<React.PropsWithChildren<ModalProps>> = ({
  children,
  isOpen,
  onClose,
}) => {
  useKey('escape', onClose)
  useLockBodyScroll(isOpen)
  const contentRef = React.useRef(null)
  const backdropRef = React.useRef(null)

  return (
    <Portal selector="#modal">
      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="modal"
        unmountOnExit
        nodeRef={contentRef}
      >
        <ModalContent data-testid="modal" ref={contentRef}>
          <TopBar>
            <Button
              data-testid="modal-close-btn"
              onClick={onClose}
              clear
              round
              icon="cross"
              aria-label="close modal"
              iconSize={16}
            />
          </TopBar>
          {children}
        </ModalContent>
      </CSSTransition>

      <CSSTransition
        in={isOpen}
        timeout={300}
        classNames="backdrop"
        unmountOnExit
        nodeRef={backdropRef}
      >
        <Backdrop data-testid="modal-backdrop" ref={backdropRef} onClick={onClose} />
      </CSSTransition>
    </Portal>
  )
}

import styled from 'styled-components'
import { useNavigate } from 'react-router-dom'
import Carousel, { type ArrowProps, type CarouselProps } from 'react-multi-carousel'

import { useFetchRestaurants } from '../../../../api/hooks'
import { IconButton } from '../../../../components/IconButton'
import { PageSection } from '../../../../components/PageSection'
import { RestaurantCard, RestaurantCardSkeleton } from '../../../../components/RestaurantCard'
import { Restaurant } from '../../../../types'
import { isMobile } from '../../../../helpers'

const PreviousButton = styled(IconButton)`
  position: absolute;
  left: 0;
`

const NextButton = styled(IconButton)`
  position: absolute;
  right: 0;
`

type RestaurantsSectionProps = {
  title: string
}

const CustomArrow = (props: Partial<CarouselProps & ArrowProps> & { isNext?: boolean }) => {
  // filter out unnecessary props coming from react-multi-carousel
  // eslint-disable-next-line @typescript-eslint/no-unused-vars
  const { carouselState, rtl, isNext, ...rest } = props
  return isNext ? (
    <NextButton name="arrow-right" {...rest} />
  ) : (
    <PreviousButton name="arrow-left" {...rest} />
  )
}

export const RestaurantsSection = ({ title }: RestaurantsSectionProps) => {
  const navigate = useNavigate()

  const { restaurants, status } = useFetchRestaurants()

  const isOnMobile = isMobile()
  return (
    <PageSection title={title}>
      <Carousel
        draggable={isOnMobile}
        partialVisible={isOnMobile}
        customLeftArrow={<CustomArrow />}
        customRightArrow={<CustomArrow isNext />}
        responsive={{
          desktop: {
            breakpoint: { max: 5000, min: 1024 },
            items: 3,
            slidesToSlide: 3,
          },
          tablet: {
            breakpoint: { max: 1024, min: 464 },
            items: 2,
            paritialVisibilityGutter: 50,
          },
          mobile: {
            breakpoint: { max: 464, min: 0 },
            items: 1,
            paritialVisibilityGutter: 30,
          },
        }}
        containerClass="carousel-container"
        removeArrowOnDeviceType={['tablet', 'mobile']}
        itemClass="carousel-item"
      >
        {status === 'loading'
          ? Array.from({ length: 3 }).map((_, index) => <RestaurantCardSkeleton key={index} />)
          : restaurants.map((restaurant: Restaurant, index: number) => (
              <RestaurantCard
                key={restaurant.name + index}
                {...restaurant}
                onClick={() => navigate(`/restaurants/${restaurant.id}`)}
              />
            ))}
      </Carousel>
    </PageSection>
  )
}

import { useCallback, useEffect, useState } from 'react'

import type { Restaurant } from '../types'

import { api } from './index'

export const useFetchRestaurants = () => {
  const [status, setStatus] = useState('idle')
  const [restaurants, setRestaurants] = useState<Restaurant[]>([])
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    setStatus('loading')

    api
      .getRestaurants()
      .then((res) => {
        setStatus('success')
        setRestaurants(res)
      })
      .catch((error) => {
        const statusCode = error?.response?.status || 500
        setStatus(statusCode.toString())
      })
  }, [retry])

  return {
    status,
    restaurants,
    retryRequest,
  }
}

export const useFetchRestaurantsByCategory = (categoryId?: string) => {
  const [status, setStatus] = useState('idle')
  const [restaurants, setRestaurants] = useState<Restaurant[]>([])
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    if (categoryId) {
      setStatus('loading')

      api
        .getRestaurantsByCategory(categoryId)
        .then((res) => {
          setStatus('success')
          setRestaurants(res)
        })
        .catch((error) => {
          const statusCode = error?.response?.status || 500
          setStatus(statusCode.toString())
        })
    }
  }, [categoryId, retry])

  return {
    status,
    restaurants,
    retryRequest,
  }
}

export const useFetchRestaurant = (id: string) => {
  const [status, setStatus] = useState('idle')
  const [restaurant, setRestaurant] = useState<Restaurant>()
  const [retry, setRetry] = useState(false)

  const retryRequest = useCallback(() => {
    setRetry((prev) => !prev)
  }, [setRetry])

  useEffect(() => {
    setStatus('loading')

    api
      .getRestaurantById(id)
      .then((res) => {
        setStatus('success')
        setRestaurant(res)
      })
      .catch((error) => {
        const statusCode = error?.response?.status || 500
        setStatus(statusCode.toString())
      })
  }, [id, retry])

  return {
    status,
    restaurant,
    retryRequest,
  }
}

