import type { Meta, StoryObj } from '@storybook/react-vite'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { expect, waitFor } from 'storybook/test'

import { RestaurantDetailPage } from './RestaurantDetailPage'

const meta = {
  component: RestaurantDetailPage,
  tags: ['ai-generated'],
  decorators: [
    (Story) => (
      <MemoryRouter initialEntries={['/restaurants/1']}>
        <Routes>
          <Route path="/restaurants/:id" element={<Story />} />
        </Routes>
      </MemoryRouter>
    ),
  ],
} satisfies Meta<typeof RestaurantDetailPage>

export default meta
type Story = StoryObj<typeof meta>

export const Default: Story = {
  play: async ({ canvas }) => {
    await waitFor(
      () => expect(canvas.getByRole('heading', { name: /Burger Kingdom/i })).toBeVisible(),
      { timeout: 5000 },
    )
  },
}

export const Loading: Story = {
  decorators: [
    (Story) => (
      <MemoryRouter initialEntries={['/restaurants/1']}>
        <Routes>
          <Route path="/restaurants/:id" element={<Story />} />
        </Routes>
      </MemoryRouter>
    ),
  ],
  play: async ({ canvas }) => {
    // Either loading spinner or the loaded content should be present
    await waitFor(
      () =>
        expect(
          canvas.queryByTestId('loading') !== null ||
          canvas.queryByRole('heading', { name: /Burger Kingdom/i }) !== null,
        ).toBe(true),
      { timeout: 5000 },
    )
  },
}

export const WithMenuItems: Story = {
  play: async ({ canvas }) => {
    await waitFor(
      () => expect(canvas.getByText(/To eat/i)).toBeVisible(),
      { timeout: 5000 },
    )
  },
}

import { http, HttpResponse } from 'msw'

import { restaurantsCompleteData } from '../src/stub/restaurants'

export const BASE_URL = 'https://mealdrop.netlify.app/.netlify/functions/restaurants'

export const mswHandlers = [
  http.get(BASE_URL, ({ request }) => {
    const url = new URL(request.url)
    const id = url.searchParams.get('id')
    const category = url.searchParams.get('category')

    if (id) {
      const restaurant = restaurantsCompleteData.find((r) => r.id === id)
      if (!restaurant) {
        return new HttpResponse(null, { status: 404 })
      }
      return HttpResponse.json(restaurant)
    }

    if (category) {
      const filtered = restaurantsCompleteData.filter((r) =>
        r.categories.includes(category)
      )
      return HttpResponse.json(filtered)
    }

    return HttpResponse.json(restaurantsCompleteData)
  }),
]

